window.PACTO.acts["dec-2007-533"]={"label": "DECISIONE 2007/533/GAI DEL CONSIGLIO", "short": "Dec. 533/2007", "file": "ext-dec-2007-533.html", "external": true, "version": "consolidato 2020-12-28", "eurlex": "https://eur-lex.europa.eu/eli/dec/2007/533/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Istituzione e scopo generale del SIS II", "anchor": "art_1", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">È istituito il sistema d’informazione Schengen di seconda generazione («SIS II»).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Scopo del SIS II è, a norma della presente decisione, assicurare un elevato livello di sicurezza nello spazio di libertà, sicurezza e giustizia dell’Unione europea, incluso il mantenimento della sicurezza pubblica e dell’ordine pubblico e la salvaguardia della sicurezza nel territorio degli Stati membri e applicare le disposizioni della parte terza, titolo IV, del trattato CE relativo alla circolazione delle persone in detto territorio avvalendosi delle informazioni trasmesse tramite tale sistema.</div>\n</div>"]]}, "2": {"label": "Articolo 2", "heading": "Ambito di applicazione", "anchor": "art_2", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La presente decisione definisce le condizioni e le procedure applicabili all’inserimento e al trattamento nel SIS II delle segnalazioni relative a persone e oggetti, allo scambio di informazioni supplementari e dati complementari per la cooperazione di polizia e giudiziaria in campo penale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La presente decisione contempla anche disposizioni sull’architettura tecnica del SIS II, sulle competenze degli Stati membri e dell’organo di gestione di cui all’articolo 15, sulle regole generali sul trattamento dei dati, sui diritti delle persone e sulla responsabilità.</div>\n</div>"]]}, "3": {"label": "Articolo 3", "heading": "Definizioni", "anchor": "art_3", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ai fini della presente decisione, si intende per:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«segnalazione»: un insieme di dati inseriti nel SIS II che permetta alle autorità competenti di identificare un individuo o un oggetto in vista di intraprendere un’azione specifica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«informazioni supplementari»: le informazioni non memorizzate nel SIS II ma connesse alle segnalazioni del SIS II, che devono essere scambiate:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per permettere agli Stati membri di consultarsi o informarsi a vicenda quando introducono una segnalazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in seguito a una risposta positiva al fine di consentire l’azione appropriata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">quando non è possibile procedere all’azione richiesta;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">con riguardo alla qualità dei dati SIS II;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">con riguardo alla compatibilità e alla priorità delle segnalazioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">con riguardo ai diritti di accesso;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«dati complementari»: i dati memorizzati nel SIS II e connessi alle segnalazioni del SIS II, che devono essere immediatamente disponibili per le autorità competenti nei casi in cui una persona i cui dati sono stati inseriti nel SIS II sia individuata grazie all’interrogazione di tale sistema;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«dati personali»: qualsiasi informazione concernente una persona fisica identificata o identificabile («persona interessata»); una persona identificabile è una persona che può essere identificata, direttamente o indirettamente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«trattamento di dati personali» («trattamento»): qualsiasi operazione o insieme di operazioni compiute con o senza l’ausilio di processi automatizzati e applicate a dati personali, come raccolta, registrazione, organizzazione, memorizzazione, adattamento o modifica, estrazione, consultazione, uso, comunicazione mediante trasmissione, diffusione o qualsiasi altra forma di messa a disposizione, raffronto o interconnessione, nonché blocco, cancellazione o distruzione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nella presente decisione qualsiasi riferimento alle disposizioni della decisione quadro 2002/584/GAI si intende fatto altresì alle corrispondenti disposizioni degli accordi conclusi tra l’Unione europea e i paesi terzi in virtù degli articoli 24 e 38 del trattato UE ai fini della consegna di persone sulla base di un mandato di arresto, che prevedono che il mandato di arresto sia trasmesso tramite il sistema di informazione Schengen.</div>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Architettura tecnica e modalità operative del SIS II", "anchor": "art_4", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il SIS II consta di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un sistema centrale («SIS II centrale») costituito da:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">un’unità di supporto tecnico («CS-SIS») contenente una banca dati, la «banca dati del SIS II»,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">un’interfaccia nazionale uniforme («NI-SIS»);</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un sistema nazionale («N.SIS II») in ciascuno Stato membro, consistente nei sistemi di dati nazionali che comunicano con il SIS II centrale. Un N.SIS II può contenere un archivio di dati («copia nazionale»), costituito da una copia completa o parziale della banca dati del SIS II;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un’infrastruttura di comunicazione fra il CS-SIS e l’NI-SIS (l'«infrastruttura di comunicazione») che è dotata di una rete virtuale cifrata dedicata ai dati SIS II e provvede allo scambio di informazioni tra uffici Sirene ai sensi dell’articolo 7, paragrafo 2.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I dati SIS II sono inseriti, aggiornati, cancellati e consultati attraverso i vari sistemi N.SIS II. La copia nazionale è disponibile ai fini dell’interrogazione automatizzata nel territorio di ciascuno degli Stati membri che usano tale copia. Non possono essere consultati gli archivi di dati contenuti nell’N.SIS II degli altri Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il CS-SIS svolge funzioni di controllo e gestione tecnici, ha sede a Strasburgo (Francia), mentre il CS SIS di riserva, in grado di assicurare tutte le funzioni del CS SIS principale in caso di guasto di tale sistema, ha sede a Sankt Johann im Pongau (Austria).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il CS-SIS fornisce i servizi necessari per l’inserimento e il trattamento dei dati SIS II, compresa la consultazione della banca dati del SIS II. Agli Stati membri che usano una copia nazionale, il CS-SIS:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornisce l’aggiornamento in linea delle copie nazionali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assicura la sincronizzazione e la coerenza tra le copie nazionali e la banca dati del SIS II;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornisce le funzioni di inizializzazione e ripristino delle copie nazionali.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "5": {"label": "Articolo 5", "heading": "Costi", "anchor": "art_5", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I costi relativi all’istituzione, all’esercizio e alla manutenzione del SIS II centrale e dell’infrastruttura di comunicazione sono a carico del bilancio generale dell’Unione europea.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Tali costi includono il lavoro effettuato con riguardo al CS-SIS per garantire la fornitura dei servizi di cui all’articolo 4, paragrafo 4.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I costi per l’istituzione, l’esercizio e la manutenzione di ciascun N.SIS II sono a carico dello Stato membro interessato.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "6": {"label": "Articolo 6", "heading": "Sistemi nazionali", "anchor": "art_6", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro è competente per l'istituzione, l'esercizio, la manutenzione e l'ulteriore sviluppo del proprio N.SIS II e per il collegamento del proprio N.SIS II all'NI-SIS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro è responsabile di garantire la disponibilità ininterrotta dei dati SIS II agli utenti finali.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "7": {"label": "Articolo 7", "heading": "Ufficio N.SIS II e ufficio Sirene", "anchor": "art_7", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ciascuno Stato membro designa un’autorità («ufficio N.SIS II») che ha la competenza centrale per il rispettivo N.SIS II.</p>\n<p class=\"norm inline-element\">Tale autorità è responsabile del corretto funzionamento e della sicurezza dell’N.SIS II, garantisce l’accesso delle autorità competenti al SIS II e adotta le misure atte a garantire l’osservanza delle disposizioni della presente decisione.</p>\n<p class=\"norm inline-element\">Ciascuno Stato membro trasmette le proprie segnalazioni per il tramite del proprio ufficio N.SIS II.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ciascuno Stato membro designa l’autorità competente per lo scambio di tutte le informazioni supplementari («ufficio Sirene») conformemente alle disposizioni del manuale Sirene di cui all’articolo 8.</p>\n<p class=\"norm inline-element\">Detti uffici coordinano inoltre la verifica della qualità delle informazioni inserite nel SIS II. A tali fini, essi hanno accesso ai dati elaborati nel SIS II.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri comunicano all’organo di gestione il rispettivo ufficio N.SIS II e ufficio Sirene. L’organo di gestione ne pubblica l’elenco insieme all’elenco di cui all’articolo 46, paragrafo 8.</div>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Scambio di informazioni supplementari", "anchor": "art_8", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le informazioni supplementari sono scambiate conformemente alle disposizioni del manuale Sirene e per il tramite dell’infrastruttura di comunicazione. In caso di indisponibilità dell’infrastruttura di comunicazione, gli Stati membri possono usare altri mezzi tecnici adeguatamente protetti per lo scambio di informazioni supplementari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le informazioni supplementari sono usate solo per lo scopo per il quale sono state trasmesse.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Alle richieste di informazioni supplementari formulate dagli altri Stati membri è data una risposta quanto più rapida possibile.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le modalità dettagliate di scambio delle informazioni supplementari sono adottate secondo la procedura di cui all’articolo 67 sotto forma di un manuale denominato «manuale Sirene», fatte salve le disposizioni dello strumento che istituisce l’organo di gestione.</div>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Compatibilità tecnica", "anchor": "art_9", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per consentire una pronta ed efficiente trasmissione dei dati, all’atto dell’istituzione del rispettivo N.SIS II ciascuno Stato membro si conforma ai protocolli e alle procedure tecniche stabiliti per assicurare la compatibilità del proprio N.SIS II con il CS-SIS. Tali protocolli e procedure tecniche sono stabiliti secondo la procedura di cui all’articolo 67, fatte salve le disposizioni dello strumento che istituisce l’organo di gestione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In caso di uso di una copia nazionale, lo Stato membro interessato provvede, tramite i servizi forniti dal CS SIS, affinché i dati memorizzati nella copia nazionale siano, grazie agli aggiornamenti automatici di cui all’articolo 4, paragrafo 4, identici e coerenti con quelli della banca dati del SIS II e un’interrogazione nella sua copia nazionale produca risultati equivalenti a quelli di un’interrogazione effettuata nella banca dati del SIS II.</div>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Sicurezza — Stati membri", "anchor": "art_10", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ciascuno Stato membro adotta, per il rispettivo N.SIS II, le misure necessarie, compreso un piano di sicurezza, per:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">proteggere fisicamente i dati, tra l’altro mediante l’elaborazione di piani di emergenza per la protezione delle infrastrutture critiche;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire alle persone non autorizzate l’accesso alle installazioni informatiche utilizzate per il trattamento di dati personali (controlli all’ingresso delle installazioni);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire che supporti di dati possano essere letti, copiati, modificati o asportati senza autorizzazione (controllo dei supporti di dati);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire che i dati siano inseriti senza autorizzazione e che i dati personali memorizzati siano visionati, modificati o cancellati senza autorizzazione (controllo dell’archiviazione);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire che persone non autorizzate usino i sistemi automatizzati di elaborazione dati mediante apparecchiature per la trasmissione di dati (controllo degli utenti);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire che le persone autorizzate a usare un sistema automatizzato di elaborazione dati possano accedere solo ai dati di loro competenza attraverso identità di utente individuali e uniche ed esclusivamente con modalità di accesso riservate (controllo dell’accesso ai dati);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assicurare che tutte le autorità con diritto di accedere al SIS II o alle installazioni di elaborazione dati creino profili che descrivano i compiti e le funzioni delle persone autorizzate ad accedere, inserire, aggiornare, cancellare e consultare i dati e mettano senza indugio tali profili a disposizione delle autorità nazionali di controllo di cui all’articolo 60 a richiesta di queste (profili personali);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire la possibilità di verificare ed accertare a quali organismi possano essere trasmessi dati personali mediante apparecchiature per la trasmissione di dati (controllo della trasmissione);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire la possibilità di verificare ed accertare a posteriori quali dati personali siano stati introdotti nei sistemi automatizzati di elaborazione dati, il momento dell’inserimento, la persona che lo ha effettuato e lo scopo dello stesso (controllo dell’inserimento);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire, in particolare mediante tecniche appropriate di cifratura, che all’atto del trasferimento di dati personali nonché del trasporto di supporti di dati essi possano essere letti, copiati, modificati o cancellati senza autorizzazione (controllo del trasporto);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">controllare l’efficacia delle misure di sicurezza di cui al presente paragrafo e adottare le necessarie misure di carattere organizzativo relative al controllo interno per garantire l’osservanza della presente decisione (autocontrollo).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano misure equivalenti a quelle del paragrafo 1 per quanto riguarda la sicurezza degli scambi di informazioni supplementari.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"]]}, "11": {"label": "Articolo 11", "heading": "Riservatezza - Stati membri", "anchor": "art_11", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro applica le proprie norme nazionali in materia di segreto professionale o altri obblighi di riservatezza equivalenti a tutti i soggetti e organismi che debbano lavorare con i dati SIS II e con le informazioni supplementari, conformemente alla propria legislazione nazionale. Tale obbligo vincola tali soggetti e organismi anche dopo che avranno rispettivamente lasciato l'incarico o cessato di lavorare, ovvero portato a termine le proprie attività.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se collabora con contraenti esterni per un qualsiasi compito relativo al SIS II, lo Stato membro monitora da vicino le attività del contraente per garantire il rispetto di tutte le disposizioni della presente decisione, in particolare sulla sicurezza, la riservatezza e la protezione dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La gestione operativa dell'N.SIS II o delle copie tecniche non può essere affidata a imprese o organizzazioni private.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "12": {"label": "Articolo 12", "heading": "Tenuta dei registri a livello nazionale", "anchor": "art_12", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri che non usano copie nazionali provvedono affinché ogni accesso ai dati personali e ogni scambio dei medesimi nell’ambito del CS-SIS sia registrato nel proprio N.SIS II per verificare la legittimità dell’interrogazione, per controllare la liceità del trattamento dei dati, ai fini dell’autocontrollo e per garantire il corretto funzionamento di N.SIS II, l’integrità e la sicurezza dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri che usano copie nazionali provvedono affinché ogni accesso ai dati SIS II e tutti gli scambi dei medesimi siano registrati ai fini di cui al paragrafo 1. Ciò non vale per i trattamenti di cui all’articolo 4, paragrafo 4.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I registri riportano, in particolare, la cronistoria delle segnalazioni, la data e l’ora della trasmissione dei dati, i dati usati per effettuare un’interrogazione, un riferimento ai dati trasmessi e il nome dell’autorità competente e del responsabile del trattamento dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I registri possono essere usati solo ai fini specificati di cui ai paragrafi 1 e 2 e sono cancellati al più presto un anno dopo e al più tardi tre anni dopo la loro creazione. I registri contenenti la cronistoria delle segnalazioni sono cancellati da uno a tre anni dopo la cancellazione delle segnalazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I registri possono essere tenuti più a lungo se sono necessari per procedure di controllo già in corso.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Le autorità nazionali competenti incaricate di verificare la legittimità dell’interrogazione, di controllare la liceità del trattamento dei dati, dell’autocontrollo e di garantire il corretto funzionamento dell’N.SIS II, l’integrità e la sicurezza dei dati hanno accesso a tali registri, nei limiti delle rispettive competenze e su loro richiesta, ai fini dell’assolvimento dei loro doveri.</div>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Autocontrollo", "anchor": "art_13", "frags": [[null, "<p class=\"norm\">Gli Stati membri provvedono affinché ogni autorità con diritto di accesso ai dati SIS II adotti le misure necessarie per assicurare l’osservanza della presente decisione e cooperi, se necessario, con l’autorità nazionale di controllo.</p>"]]}, "14": {"label": "Articolo 14", "heading": "Formazione del personale", "anchor": "art_14", "frags": [[null, "<p class=\"norm\">Prima di essere autorizzato a elaborare dati memorizzati nel SIS II, il personale delle autorità con diritto di accesso al SIS II riceve una formazione adeguata sulle norme in materia di sicurezza e di protezione dei dati ed è informato dei reati e delle sanzioni pertinenti.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "15": {"label": "Articolo 15", "heading": "Gestione operativa", "anchor": "art_15", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Dopo un periodo transitorio un organo di gestione (l’«organo di gestione»), finanziato dal bilancio generale dell’Unione europea, è responsabile della gestione operativa del SIS II centrale. L’organo di gestione, in collaborazione con gli Stati membri, provvede affinché in ogni momento le migliori tecnologie disponibili, fatta salva un’analisi costi-benefici, siano utilizzate per il SIS II centrale.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’organo di gestione è responsabile altresì di tutti i compiti connessi con l’infrastruttura di comunicazione, in particolare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">controllo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sicurezza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">coordinamento dei rapporti tra gli Stati membri e il gestore;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">compiti relativi all’esecuzione del bilancio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">acquisizione e rinnovo; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">aspetti contrattuali.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">L'organo di gestione sviluppa e gestisce un meccanismo e procedure per lo svolgimento dei controlli di qualità sui dati contenuti nel CS-SIS.</div>\n</div>"], [null, "<p class=\"norm\">Esso riferisce periodicamente agli Stati membri a tale riguardo. L'organo di gestione riferisce periodicamente alla Commissione in merito ai problemi incontrati, dandone comunicazione anche agli Stati membri interessati.</p>"], [null, "<p class=\"norm\">La Commissione riferisce periodicamente al Parlamento europeo e al Consiglio in merito ai problemi di qualità dei dati incontrati.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Durante un periodo transitorio, prima che l’organo di gestione assuma le sue responsabilità, la Commissione è responsabile della gestione operativa del SIS II centrale. La Commissione può delegare tale compito e compiti relativi all’esecuzione del bilancio a organismi nazionali del settore pubblico di due diversi paesi, a norma del regolamento (CE, Euratom) n. 1605/2002 del Consiglio, del 25 giugno 2002, che stabilisce il regolamento finanziario applicabile al bilancio generale delle Comunità europee (\n<span class=\"superscript\">1</span>\n).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ogni organismo nazionale del settore pubblico di cui al paragrafo 4 soddisfa, in particolare, i seguenti criteri di selezione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">deve dimostrare che ha maturato una lunga esperienza nell’esercizio di un sistema d’informazione su larga scala dotato delle funzioni di cui all’articolo 4, paragrafo 4;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">deve possedere conoscenze specialistiche notevoli in materia di requisiti di funzionamento e di sicurezza di un sistema d’informazione dotato di funzioni paragonabili a quelle di cui all’articolo 4, paragrafo 4;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">deve disporre di un personale sufficiente ed esperto, con competenze professionali e conoscenze linguistiche adeguate per lavorare in un ambiente di cooperazione internazionale come quello richiesto dal SIS II;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">deve disporre di un’infrastruttura sicura costituita da installazioni e appositamente costruita, capace, in particolare, di sostenere e garantire il funzionamento continuo di sistemi IT su larga scala; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il suo contesto amministrativo deve permettergli di adempiere adeguatamente ai propri compiti ed evitare conflitti d’interesse.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Prima di ogni delega di cui al paragrafo 4 e poi a intervalli regolari, la Commissione informa il Parlamento europeo e il Consiglio in merito alle condizioni della delega, alla sua portata precisa e agli organismi ai quali i compiti sono delegati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Qualora durante il periodo transitorio la Commissione deleghi la propria responsabilità a norma del paragrafo 4, provvede ad assicurare che tale delega rispetti pienamente i limiti posti dal sistema istituzionale stabilito nel trattato CE. Essa assicura in particolare che la delega non si ripercuota negativamente sull’efficacia dei meccanismi di controllo previsti dal diritto dell’Unione europea, siano essi a cura della Corte di giustizia, della Corte dei conti o del garante europeo della protezione dei dati.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">La gestione operativa del SIS II centrale consiste nell'insieme dei compiti necessari al funzionamento del SIS II centrale 24 ore su 24 e 7 giorni su 7, ai sensi della presente decisione, e comprende in particolare le attività di manutenzione e gli adattamenti tecnici necessari per il buon funzionamento del sistema. Tali compiti comprendono anche il coordinamento, la gestione e il sostegno delle attività di collaudo per il SIS II centrale e i N.SIS II che garantiscono che il SIS II centrale e i N.SIS II operino secondo i requisiti per la conformità tecnica di cui all'articolo 9.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "16": {"label": "Articolo 16", "heading": "Sicurezza", "anchor": "art_16", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’organo di gestione e la Commissione adottano, rispettivamente per il SIS II centrale e per l’infrastruttura di comunicazione le misure necessarie, compreso un piano di sicurezza, per:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">proteggere fisicamente i dati, tra l’altro mediante l’elaborazione di piani di emergenza per la protezione delle infrastrutture critiche;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire alle persone non autorizzate l’accesso alle installazioni informatiche utilizzate per il trattamento di dati personali (controlli all’ingresso delle installazioni);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire che supporti di dati possano essere letti, copiati, modificati o asportati senza autorizzazione (controllo dei supporti di dati);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire che i dati siano inseriti senza autorizzazione e che i dati personali memorizzati siano visionati, modificati o cancellati senza autorizzazione (controllo dell’archiviazione);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire che persone non autorizzate usino i sistemi automatizzati di elaborazione dati mediante apparecchiature per la trasmissione di dati (controllo degli utenti);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire che le persone autorizzate a usare un sistema automatizzato di elaborazione dati possano accedere solo ai dati di loro competenza attraverso identità di utente individuali e uniche ed esclusivamente con modalità di accesso riservate (controllo dell’accesso ai dati);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">creare profili che descrivano i compiti e le funzioni delle persone autorizzate ad accedere ai dati o alle installazioni informatiche e mettere senza indugio tali profili a disposizione del garante europeo della protezione dei dati di cui all’articolo 61 a richiesta di quest’ultimo (profili personali);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire la possibilità di verificare ed accertare a quali organismi possano essere trasmessi dati personali mediante apparecchiature per la trasmissione di dati (controllo della trasmissione);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire la possibilità di verificare ed accertare a posteriori quali dati personali siano stati introdotti nei sistemi automatizzati di elaborazione dati, il momento dell’inserimento e la persona che lo ha effettuato (controllo dell’inserimento);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire, in particolare mediante tecniche appropriate di cifratura, che all’atto del trasferimento di dati personali nonché del trasporto di supporti di dati essi possano essere letti, copiati, modificati o cancellati senza autorizzazione (controllo del trasporto);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">controllare l’efficacia delle misure di sicurezza di cui al presente paragrafo e adottare le necessarie misure di carattere organizzativo relative al controllo interno per garantire l’osservanza della presente decisione (autocontrollo).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’organo di gestione adotta misure equivalenti a quelle di cui al paragrafo 1 per quanto riguarda la sicurezza degli scambi di informazioni supplementari attraverso l’infrastruttura di comunicazione.</div>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Riservatezza — Organo di gestione", "anchor": "art_17", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 17 dello statuto dei funzionari delle Comunità europee, l’organo di gestione applica norme adeguate in materia di segreto professionale o altri obblighi di riservatezza equivalenti a tutti i membri del proprio personale che debbano lavorare con i dati SIS II, secondo standard equiparabili a quelli previsti all’articolo 11 della presente decisione. Tale obbligo vincola gli interessati anche dopo che avranno rispettivamente lasciato l’incarico o cessato di lavorare, ovvero portato a termine le proprie attività.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’organo di gestione adotta misure equivalenti a quelle di cui al paragrafo 1 per quanto riguarda la riservatezza degli scambi di informazioni supplementari attraverso l’infrastruttura di comunicazione.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se collabora con contraenti esterni per un qualsiasi compito relativo al SIS II, l'organo di gestione monitora da vicino le attività del contraente per garantire il rispetto di tutte le disposizioni della presente decisione, in particolare sulla sicurezza, la riservatezza e la protezione dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La gestione operativa del CS-SIS non può essere affidata a imprese o organizzazioni private.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "18": {"label": "Articolo 18", "heading": "Tenuta dei registri a livello centrale", "anchor": "art_18", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’organo di gestione provvede affinché ogni accesso e ogni scambio di dati personali nell’ambito del CS-SIS siano registrati ai fini di cui all’articolo 12, paragrafi 1 e 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I registri riportano, in particolare, la cronistoria delle segnalazioni, la data e l’ora della trasmissione dei dati, i dati usati per effettuare interrogazioni, il riferimento ai dati trasmessi e l’identità dell’autorità competente responsabile del trattamento dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I registri possono essere usati solo ai fini di cui al paragrafo 1 e sono cancellati al più presto un anno dopo e al più tardi tre anni dopo la loro creazione. I registri contenenti la cronistoria delle segnalazioni sono cancellati da uno a tre anni dopo la cancellazione delle segnalazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I registri possono essere tenuti più a lungo se sono necessari per procedure di controllo in corso.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le autorità competenti incaricate di verificare la legittimità di un’interrogazione, di controllare la liceità del trattamento dei dati, dell’autocontrollo e di garantire il corretto funzionamento del CS-SIS, l’integrità e la sicurezza dei dati hanno accesso a tali registri, nei limiti delle rispettive competenze e su loro richiesta, ai fini dell’assolvimento dei loro doveri.</div>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Campagna informativa", "anchor": "art_19", "frags": [[null, "<p class=\"norm\">La Commissione, in collaborazione con le autorità nazionali di controllo e con il garante europeo della protezione dei dati, lancia, in concomitanza con l’entrata in funzione del SIS II, una campagna informativa rivolta al pubblico sugli obiettivi, i dati memorizzati, le autorità che vi hanno accesso e i diritti delle persone. Una volta istituito, l’organo di gestione, in collaborazione con le autorità nazionali di controllo e con il garante europeo della protezione dei dati, ripete siffatte campagne a intervalli regolari. Gli Stati membri, in collaborazione con le autorità nazionali di controllo, definiscono e attuano le politiche necessarie per informare i propri cittadini sul SIS II in generale.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "20": {"label": "Articolo 20", "heading": "Categorie di dati", "anchor": "art_20", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fatti salvi l’articolo 8, paragrafo 1, o le disposizioni della presente decisione che prevedono la memorizzazione di dati complementari, il SIS II contiene esclusivamente le categorie di dati forniti da ciascuno Stato membro, come richiesto ai fini previsti negli articoli 26, 32, 34, 36 e 38.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le categorie di dati sono le seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le persone segnalate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli oggetti di cui agli articoli 36 e 38.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le informazioni sulle persone segnalate si limitano alle seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognomi e nomi, cognomi alla nascita, eventuali cognomi precedenti e «alias» che possono essere registrati a parte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">segni fisici particolari, oggettivi ed inalterabili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">luogo e data di nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fotografie;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impronte digitali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cittadinanza(e);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">indicazione che la persona in questione è armata, violenta o è evasa;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ragione della segnalazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">autorità che effettua la segnalazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">riferimento alla decisione che ha dato origine alla segnalazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">azione da intraprendere;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">connessioni con altre segnalazioni già introdotte nel SIS II a norma dell’articolo 52;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>n) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tipo di reato.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le norme tecniche necessarie per l’inserimento, l’aggiornamento, la cancellazione e la consultazione dei dati di cui ai paragrafi 2 e 3 sono stabilite secondo la procedura di cui all’articolo 67, fatte salve le disposizioni dello strumento che istituisce l’organo di gestione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le norme tecniche necessarie per la consultazione dei dati di cui al paragrafo 3 sono analoghe per le consultazioni nel CS-SIS, nelle copie nazionali e nelle copie tecniche, di cui all’articolo 46, paragrafo 2.</div>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Proporzionalità", "anchor": "art_21", "frags": [[null, "<p class=\"norm\">Prima di effettuare una segnalazione lo Stato membro verifica se l’adeguatezza, la pertinenza e l’importanza del caso giustificano l’inserimento della segnalazione nel SIS II.</p>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<p class=\"norm\">Allorché si ricerchi una persona o un oggetto nell'ambito di una segnalazione connessa a un reato di terrorismo, il caso è ritenuto adeguato, pertinente e sufficientemente importante da giustificare l'esistenza della segnalazione nel SIS II. Per motivi di sicurezza pubblica o nazionale, gli Stati membri possono eccezionalmente astenersi dall'inserire una segnalazione, quando la stessa rischi di ostacolare indagini, inchieste o procedimenti ufficiali o giudiziari.</p>"], [null, "<p class=\"modref\">\n▼M2\n</p>"]]}, "22": {"label": "Articolo 22", "heading": "Norme specifiche per l'inserimento, la verifica o l'interrogazione tramite fotografie e impronte digitali", "anchor": "art_22", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fotografie e impronte digitali possono essere inserite solo previo controllo speciale di qualità per accertare che soddisfino gli standard minimi di qualità dei dati. Le specifiche sul controllo speciale di qualità sono stabilite secondo la procedura di cui all'articolo 67.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora siano disponibili dati relativi alle fotografie e alle impronte digitali in una segnalazione nel SIS II, tali fotografie e impronte digitali sono usati per confermare l'identità di una persona reperita grazie all'interrogazione del SIS II con dati alfanumerici.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I dati relativi alle impronte digitali possono essere consultati in tutti i casi per identificare una persona. Tuttavia, i dati relativi alle impronte digitali devono essere consultati a fini di identificazione se l'identità della persona non può essere accertata con altri mezzi. A tal fine il SIS II centrale contiene un sistema automatico per il riconoscimento delle impronte digitali (AFIS).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I dati relativi alle impronte digitali nel SIS II in relazione a segnalazioni inserite a norma degli articoli 26, 32 e 36 possono essere consultati anche usando serie complete o incomplete di impronte digitali rinvenute sul luogo di un reato grave o di un reato di terrorismo oggetto di indagine, qualora si possa stabilire con un elevato grado di probabilità che quelle serie di impronte appartengono a un autore del reato, e purché l'interrogazione sia effettuata simultaneamente nelle pertinenti banche dati nazionali di impronte digitali dello Stato membro.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "23": {"label": "Articolo 23", "heading": "Requisito per inserire una segnalazione", "anchor": "art_23", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Non si possono inserire segnalazioni su persone in mancanza dei dati di cui all’articolo 20, paragrafo 3, lettere a), d), l) e, ove applicabile, k).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se disponibili, sono inseriti anche tutti gli altri dati di cui all’articolo 20, paragrafo 3.</div>\n</div>"]]}, "24": {"label": "Articolo 24", "heading": "Disposizioni generali relative agli indicatori di validità", "anchor": "art_24", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualora uno Stato membro reputi che dare applicazione ad una segnalazione inserita a norma degli articoli 26, 32 o 36 non sia compatibile con la legislazione nazionale, con i propri obblighi internazionali o con interessi nazionali essenziali, può esigere a posteriori che alla segnalazione sia apposto un indicatore di validità affinché non sia eseguita sul proprio territorio l’azione richiesta nella segnalazione. L’indicatore di validità è apposto dall’ufficio Sirene dello Stato membro che ha inserito la segnalazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per consentire agli Stati membri di esigere l’apposizione di un indicatore di validità a una segnalazione effettuata a norma dell’articolo 26, tutti gli Stati membri sono automaticamente informati di ogni nuova segnalazione di questa categoria mediante lo scambio di informazioni supplementari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se per ragioni particolarmente gravi e urgenti lo Stato membro che ha emesso la segnalazione chiede l’esecuzione dell’azione, lo Stato membro che ha effettuato la segnalazione esamina se può acconsentire al ritiro dell’indicatore di validità di cui ha richiesto l’apposizione. Se vi può acconsentire, esso adotta le misure necessarie per far sì che l’azione richiesta sia eseguita immediatamente.</div>\n</div>"]]}, "25": {"label": "Articolo 25", "heading": "Indicatori di validità relativi a segnalazioni per l’arresto a fini di consegna", "anchor": "art_25", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ove si applichi la decisione quadro 2002/584/GAI, l’indicatore di validità che impedisca l’arresto è apposto a una segnalazione per l’arresto a fini di consegna solo se l’autorità giudiziaria competente in virtù della legislazione nazionale per l’esecuzione del mandato di arresto europeo ne ha rifiutato l’esecuzione per motivi di non esecuzione e se l’apposizione dell’indicatore di validità è stata richiesta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Tuttavia, su richiesta di un’autorità giudiziaria competente in virtù della legislazione nazionale, in base a un’istruzione generale o in un caso specifico, si può chiedere di apporre un indicatore di validità anche se risulta in modo evidente che l’esecuzione del mandato di arresto europeo dovrà essere rifiutata.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "26": {"label": "Articolo 26", "heading": "Obiettivi e condizioni della segnalazione", "anchor": "art_26", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I dati relativi alle persone ricercate per l’arresto a fini di consegna sulla scorta di un mandato d’arresto europeo, ovvero per l’arresto a fini di estradizione, sono inseriti su richiesta dell’autorità giudiziaria dello Stato membro della segnalazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I dati relativi alle persone ricercate per l’arresto a fini di consegna sono del pari inseriti sulla scorta di mandati di arresto emessi in conformità degli accordi conclusi tra l’Unione europea e i paesi terzi in virtù degli articoli 24 e 38 del trattato UE ai fini della consegna di persone sulla base di un mandato di arresto che prevedono la trasmissione di detto mandato di arresto mediante il sistema d’informazione Schengen.</div>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Dati complementari su persone ricercate per l’arresto a fini di consegna", "anchor": "art_27", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Nel caso di persone ricercate per l’arresto a fini di consegna sulla scorta di un mandato d’arresto europeo, lo Stato membro della segnalazione inserisce nel SIS II una copia del mandato d’arresto europeo originale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Lo Stato membro della segnalazione può inserire una copia della traduzione del mandato d’arresto europeo in una o più lingue ufficiali dell’Unione europea.</div>\n</div>"]]}, "28": {"label": "Articolo 28", "heading": "Informazioni supplementari su persone ricercate per l’arresto a fini di consegna", "anchor": "art_28", "frags": [[null, "<p class=\"norm\">Lo Stato membro che ha inserito la segnalazione nel SIS II per l’arresto a fini di consegna comunica le informazioni di cui all’articolo 8, paragrafo 1, della decisione quadro 2002/584/GAI a tutti gli Stati membri tramite lo scambio di informazioni supplementari.</p>"]]}, "29": {"label": "Articolo 29", "heading": "Informazioni supplementari su persone ricercate per l’arresto a fini di estradizione", "anchor": "art_29", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Lo Stato membro che ha inserito la segnalazione nel SIS II a fini di estradizione comunica i dati seguenti a tutti gli Stati membri mediante lo scambio di informazioni supplementari:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">autorità da cui proviene la richiesta di arresto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esistenza di un mandato d’arresto o di un documento avente la medesima valenza giuridica, o di una sentenza esecutiva;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">natura e qualificazione giuridica del reato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">descrizione delle circostanze in cui il reato è stato commesso, compreso il momento, il luogo ed il grado di partecipazione al reato della persona segnalata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per quanto possibile, le conseguenze del reato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualsiasi altra informazione utile o necessaria per l’esecuzione della segnalazione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I dati menzionati nel paragrafo 1 non sono comunicati se i dati di cui agli articoli 27 o 28 sono già stati forniti e sono considerati sufficienti per l’esecuzione della segnalazione dallo Stato membro interessato.</div>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Conversione delle segnalazioni su persone ricercate per l’arresto a fini di consegna o di estradizione", "anchor": "art_30", "frags": [[null, "<p class=\"norm\">Se non è possibile procedere ad un arresto a causa di una decisione di rifiuto emessa da uno Stato membro richiesto secondo le procedure relative agli indicatori di validità di cui agli articoli 24 o 25 o, nel caso di una segnalazione per l’arresto a fini di estradizione, in quanto un’indagine non è ancora stata conclusa, lo Stato membro richiesto deve considerare la segnalazione come una segnalazione per comunicare il luogo di soggiorno della persona interessata.</p>"]]}, "31": {"label": "Articolo 31", "heading": "Esecuzione dell’azione richiesta nella segnalazione di una persona ricercata per l’arresto in vista della consegna o dell’estradizione", "anchor": "art_31", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Una segnalazione inserita nel SIS II a norma dell’articolo 26 unitamente ai dati complementari di cui all’articolo 27 costituisce ed ha lo stesso effetto di un mandato d’arresto europeo emesso a norma della decisione quadro 2002/584/GAI, ove si applichi tale decisione quadro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ove non si applichi la decisione quadro 2002/584/GAI, una segnalazione inserita nel SIS II a norma degli articoli 26 e 29 ha la stessa valenza giuridica di una richiesta di arresto provvisorio a norma dell’articolo 16 della convenzione europea di estradizione del 13 dicembre 1957 o dell’articolo 15 del trattato di estradizione e di assistenza giudiziaria in materia penale tra il Regno del Belgio, il Granducato di Lussemburgo e il Regno dei Paesi Bassi, del 27 giugno 1962.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "32": {"label": "Articolo 32", "heading": "Obiettivi e condizioni delle segnalazioni", "anchor": "art_32", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I dati relativi alle persone scomparse che devono essere poste sotto protezione e/o a quelle il cui luogo di soggiorno deve essere accertato sono inseriti nel SIS II su richiesta dell’autorità competente dello Stato membro che effettua la segnalazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Possono essere inserite le seguenti categorie di persone scomparse:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone scomparse che devono essere poste sotto protezione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ai fini della loro tutela;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per prevenire minacce;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone scomparse che non devono essere poste sotto protezione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il paragrafo 2, lettera a), si applica solo alle persone che devono essere internate per decisione di un’autorità competente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I paragrafi 1, 2 e 3 si applicano in particolare ai minori.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri assicurano che i dati inseriti nel SIS II indichino in quale delle categorie di cui al paragrafo 2 rientra la persona scomparsa.</div>\n</div>"]]}, "33": {"label": "Articolo 33", "heading": "Esecuzione dell’azione richiesta nelle segnalazioni", "anchor": "art_33", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In caso di individuazione di una persona di cui all’articolo 32, le autorità competenti comunicano, fatto salvo il paragrafo 2, il suo luogo di soggiorno allo Stato membro che effettua la segnalazione. Nei casi di cui all’articolo 32, paragrafo 2, lettera a), essa può, qualora la legislazione nazionale lo consenta, porre la suddetta persona sotto protezione per impedirle di proseguire il viaggio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La comunicazione, diversa da quella fra le autorità competenti, dei dati di una persona scomparsa maggiorenne che sia stata individuata è subordinata al consenso della persona in questione. Tuttavia, le autorità competenti possono comunicare la cancellazione della segnalazione, dovuta alla localizzazione della persona, alla persona che ne ha segnalato la scomparsa.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "34": {"label": "Articolo 34", "heading": "Obiettivi e condizioni della segnalazione", "anchor": "art_34", "frags": [[null, "<p class=\"norm\">Ai fini della comunicazione della residenza o del domicilio, gli Stati membri inseriscono nel SIS II, su richiesta dell’autorità competente, i dati relativi a:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">testimoni;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone citate a comparire o persone ricercate affinché si presentino dinanzi all’autorità giudiziaria nell’ambito di un procedimento penale per rispondere di fatti che sono loro ascritti;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone alle quali deve essere notificata una sentenza penale o altri documenti connessi con un procedimento penale per rispondere di fatti che sono stati loro ascritti;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone alle quali deve essere notificata una richiesta di presentarsi per scontare una pena privativa della libertà.</p>\n</div>\n</div>"]]}, "35": {"label": "Articolo 35", "heading": "Esecuzione dell’azione richiesta nelle segnalazioni", "anchor": "art_35", "frags": [[null, "<p class=\"norm\">Le informazioni richieste sono comunicate allo Stato membro richiedente tramite scambio di informazioni supplementari.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "36": {"label": "Articolo 36", "heading": "Obiettivi e condizioni della segnalazione", "anchor": "art_36", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I dati relativi alle persone o a veicoli, natanti, aeromobili e container sono inseriti, nel rispetto della legislazione nazionale dello Stato membro che effettua la segnalazione, ai fini di un controllo discreto o di un controllo specifico, a norma dell’articolo 37, paragrafo 4.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Tale segnalazione può essere effettuata ai fini della repressione di reati e per prevenire minacce alla sicurezza pubblica:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora esistano indizi concreti che una persona intenda commettere o commetta un reato grave, quali i reati di cui all’articolo 2, paragrafo 2, della decisione quadro 2002/584/GAI; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora la valutazione globale di una persona, in particolare sulla base dei reati commessi sino a quel momento, faccia supporre che commetterà anche in avvenire reati gravi, quali i reati di cui all’articolo 2, paragrafo 2, della decisione quadro 2002/584/GAI.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Inoltre, una segnalazione può essere effettuata conformemente alla legislazione nazionale, su richiesta delle autorità competenti per la sicurezza nazionale, qualora esistano indizi concreti che le informazioni di cui all’articolo 37, paragrafo 1, sono necessarie per prevenire una minaccia grave proveniente dall’interessato o altre minacce gravi per la sicurezza interna o esterna dello Stato. Lo Stato membro che effettua la segnalazione a norma del presente paragrafo ne informa gli altri Stati membri. Ciascuno Stato membro stabilisce a quali autorità sono trasmesse queste informazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le segnalazioni relative a veicoli, natanti, aeromobili e container possono essere effettuate qualora esistano indizi concreti che sono connesse con i reati gravi di cui al paragrafo 2 o con le minacce gravi di cui al paragrafo 3.</div>\n</div>"]]}, "37": {"label": "Articolo 37", "heading": "Esecuzione dell’azione richiesta nelle segnalazioni", "anchor": "art_37", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nell’ambito del controllo discreto o del controllo specifico, le seguenti informazioni sono raccolte e trasmesse, totalmente o in parte, all’autorità che effettua la segnalazione, in occasione di controlli alla frontiera o di altri controlli di polizia e doganali effettuati all’interno di uno Stato membro:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il fatto che siano stati individuati la persona o il veicolo, il natante, l’aeromobile o il container segnalati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il luogo, il momento o il motivo del controllo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’itinerario e la destinazione del viaggio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le persone che accompagnano gli interessati o gli occupanti del veicolo, del natante o dell’aeromobile di cui si può ragionevolmente presumere che siano associati agli interessati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il veicolo, il natante, l’aeromobile o il container usato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli oggetti trasportati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le circostanze in cui la persona o il veicolo, il natante, l’aeromobile o il container sono stati individuati.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le informazioni di cui al paragrafo 1 sono trasmesse mediante lo scambio di informazioni supplementari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Per la raccolta delle informazioni di cui al paragrafo 1, gli Stati membri provvedono affinché non sia compromesso il carattere discreto del controllo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Nell’ambito dei controlli specifici, le persone, i veicoli, i natanti, gli aeromobili, i container e gli oggetti trasportati possono essere perquisiti conformemente alla legislazione nazionale, per i fini di cui all’articolo 36. Se la legge di uno Stato membro non lo autorizza, il controllo specifico viene automaticamente convertito, per quello Stato membro, in controllo discreto.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "38": {"label": "Articolo 38", "heading": "Obiettivi e condizioni della segnalazione", "anchor": "art_38", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I dati relativi agli oggetti ricercati a scopo di sequestro o di prova in un procedimento penale sono inseriti nel SIS II.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Sono inserite le categorie di oggetti agevolmente identificabili indicate in appresso:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">veicoli a motore di cilindrata superiore a 50 cc, natanti e aeromobili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rimorchi di peso a vuoto superiore a 750 kg, roulotte, apparecchiature industriali, motori fuoribordo e container;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">armi da fuoco;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">documenti vergini rubati, altrimenti sottratti o smarriti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">documenti di identità rilasciati, quali passaporti, carte d’identità, patenti di guida, titoli di soggiorno e documenti di viaggio rubati, altrimenti sottratti, smarriti o falsificati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">certificati di immatricolazione per veicoli e targhe di veicoli rubati, altrimenti sottratti, smarriti o falsificati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">banconote (banconote registrate);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">valori mobiliari e mezzi di pagamento, quali assegni, carte di credito, obbligazioni, titoli e azioni, rubati, altrimenti sottratti, smarriti o falsificati.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le norme tecniche necessarie per l’inserimento, l’aggiornamento, la cancellazione e la consultazione dei dati di cui al paragrafo 2 sono stabilite secondo la procedura di cui all’articolo 67, fatte salve le disposizioni dello strumento che istituisce l’organo di gestione.</div>\n</div>"]]}, "39": {"label": "Articolo 39", "heading": "Esecuzione dell’azione richiesta nelle segnalazioni", "anchor": "art_39", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualora dall’interrogazione emerga l’esistenza di una segnalazione per un oggetto individuato, l’autorità che la constata si mette in contatto con l’autorità che ha effettuato la segnalazione per concordare le misure necessarie. A tale scopo, possono altresì essere trasmessi dati personali, a norma della presente decisione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le informazioni di cui al paragrafo 1 sono comunicate mediante lo scambio di informazioni supplementari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo Stato membro che ha rinvenuto l’oggetto adotta misure conformi alla propria legislazione.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "40": {"label": "Articolo 40", "heading": "Autorità con diritto di accesso alle segnalazioni", "anchor": "art_40", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’accesso ai dati inseriti nel SIS II e il diritto di consultarli direttamente o su una copia di dati del SIS II sono riservati esclusivamente alle autorità responsabili:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dei controlli di frontiera, a norma del regolamento (CE) n. 562/2006 del Parlamento europeo e del Consiglio, del 15 marzo 2006, che istituisce un codice comunitario relativo al regime di attraversamento delle frontiere da parte delle persone (codice frontiere Schengen) (\n<span class=\"superscript\">2</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">degli altri controlli di polizia e doganali effettuati all’interno dello Stato membro interessato e del relativo coordinamento da parte delle autorità designate.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Tuttavia, il diritto di accesso ai dati inseriti nel SIS II e il diritto di consultarli direttamente possono essere esercitati anche dalle autorità giudiziarie nazionali, comprese quelle responsabili dell’avvio dell’azione penale e delle indagini giudiziarie prima dell’imputazione, nell’assolvimento dei loro doveri, come previsto nella legislazione nazionale, e dalle relative autorità di coordinamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le autorità di cui al presente articolo sono inserite nell’elenco di cui all’articolo 46, paragrafo 8.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"]]}, "41": {"label": "Articolo 41", "heading": "Accesso di Europol ai dati nel SIS II", "anchor": "art_41", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'Agenzia dell'Unione europea per la cooperazione nell'attività di contrasto (Europol), istituita dal regolamento (UE) 2016/794 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">3</span>\n) ove necessario all'adempimento del suo mandato, ha il diritto di accedere ai dati nel SIS II e di consultarli. Europol può altresì scambiare e richiedere ulteriori informazioni supplementari in conformità delle disposizioni del manuale SIRENE.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora un'interrogazione effettuata da Europol riveli la presenza di una segnalazione nel SIS II, Europol ne informa lo Stato membro segnalante tramite lo scambio di informazioni supplementari a mezzo dell'infrastruttura di comunicazione e conformemente alle disposizioni del manuale SIRENE. Finché non è in grado di utilizzare le funzionalità previste per lo scambio di informazioni supplementari, Europol informa lo Stato membro segnalante tramite i canali definiti dal regolamento (UE) 2016/794.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Europol può trattare le informazioni supplementari fornitele dagli Stati membri al fine di raffrontarle con le proprie banche dati e i progetti di analisi operativa, allo scopo di identificare collegamenti o altri nessi pertinenti e per analisi strategiche, tematiche od operative di cui all'articolo 18, paragrafo 2, lettere a), b) e c), del regolamento (UE) 2016/794. Qualsiasi trattamento di informazioni supplementari da parte di Europol ai fini del presente articolo è effettuato in conformità a tale regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L'uso da parte di Europol delle informazioni ottenute tramite un'interrogazione del SIS II o tramite il trattamento di informazioni supplementari è soggetto al consenso dello Stato membro segnalante. Se lo Stato membro acconsente all'uso di tali informazioni, il loro trattamento da parte di Europol è disciplinato dal regolamento (UE) 2016/794. Le informazioni sono trasmesse da Europol a paesi terzi e organismi terzi solo con il consenso dello Stato membro segnalante e nel pieno rispetto della normativa dell'Unione in materia di protezione dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Europol:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fatti salvi i paragrafi 4 e 6, non collega parti del SIS II, né trasferisce i dati in esso contenuti cui ha accesso, a sistemi di raccolta e trattamento di dati gestito da o presso di essa e non scarica o copia altrimenti parti del SIS II;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in deroga all'articolo 31, paragrafo 1, del regolamento (UE) 2016/794, cancella le informazioni supplementari contenenti dati personali entro un anno dalla cancellazione della relativa segnalazione. A titolo di deroga, se Europol dispone di informazioni nelle proprie banche dati o nei progetti di analisi operativa su un caso cui si riferiscono le informazioni supplementari, Europol può, in via eccezionale, continuare a conservare le informazioni supplementari per svolgere i suoi compiti, ove necessario. Europol informa lo Stato membro segnalante e quello di esecuzione dell'ulteriore conservazione di tali informazioni supplementari e fornisce una giustificazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">limita l'accesso ai dati nel SIS II, comprese le informazioni supplementari, al proprio personale specificamente autorizzato che necessita dell'accesso a tali dati ai fini dell'assolvimento dei propri compiti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta e applica misure per garantire la sicurezza, la riservatezza e l'autocontrollo a norma degli articoli 10, 11 e 13;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvede affinché il proprio personale autorizzato a trattare i dati SIS II riceva una formazione e informazioni adeguate a norma dell'articolo 14;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fatto salvo il regolamento (UE) 2016/794, consente al Garante europeo della protezione dei dati di sorvegliare ed esaminare le attività da essa svolte nell'esercizio del suo diritto di accesso ai dati nel SIS II e di consultazione degli stessi e nello scambio e nel trattamento di informazioni supplementari.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Europol può duplicare i dati dal SIS II soltanto per fini tecnici, sempreché tale duplicazione sia necessaria per la consultazione diretta da parte del personale debitamente autorizzato di Europol. La presente decisione si applica a tali copie. La copia tecnica è usata al fine di conservare i dati SIS II mentre tali dati sono consultati. Una volta consultati i dati, la copia è cancellata. Tali usi non sono considerati scaricamento o duplicazione illeciti di dati SIS II. Europol si astiene dal copiare in altri sistemi di Europol i dati di una segnalazione o i dati complementari trasmessi dagli Stati membri o dal CS-SIS II.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Per verificare la liceità del trattamento dei dati, per l'autocontrollo e per garantire un'adeguata sicurezza e integrità dei dati, Europol conserva registri di tutti gli accessi al SIS II e le interrogazioni del SIS II in conformità delle disposizioni dell'articolo 12. Tali registri e tale documentazione non sono considerati scaricamenti o duplicazioni illeciti di parti del SIS II.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Gli Stati membri informano Europol, tramite lo scambio di informazioni supplementari, in merito a qualsiasi riscontro positivo (hit) su segnalazioni relative a reati di terrorismo. Gli Stati membri possono eccezionalmente non informare Europol, se ciò comprometterebbe le indagini in corso, la sicurezza di una persona, o sarebbe in contrasto con gli interessi essenziali della sicurezza dello Stato membro segnalante.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Il paragrafo 8 si applica a decorrere dalla data in cui Europol è in grado di ricevere informazioni supplementari in conformità del paragrafo 1.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "42": {"label": "Articolo 42", "heading": "Accesso dell’Eurojust ai dati SIS II", "anchor": "art_42", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I membri nazionali dell’Eurojust e i loro assistenti, nell’ambito del loro mandato, hanno il diritto di accesso ai dati inseriti nel SIS II a norma degli articoli 26, 32, 34 e 38 e di consultazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora un’interrogazione effettuata da un membro nazionale dell’Eurojust riveli la presenza di una segnalazione nel SIS II, il membro nazionale informa al riguardo lo Stato membro che ha effettuato la segnalazione. Qualsiasi informazione ottenuta a seguito di detta interrogazione può essere comunicata a paesi terzi e organismi terzi solo con il consenso dello Stato membro che ha effettuato la segnalazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">È inteso che il presente articolo non pregiudica in alcun modo le disposizioni della decisione 2002/187/GAI concernenti la protezione dei dati e la responsabilità per eventuali trattamenti non autorizzati o scorretti di tali dati da parte dei membri nazionali dell’Eurojust o dei loro assistenti, né le competenze dell’autorità di controllo comune istituita a norma di detta decisione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ogni accesso e consultazione effettuati da un membro nazionale dell’Eurojust o da un assistente è registrata secondo il disposto dell’articolo 12 e ogni uso dei dati ai quali ha avuto accesso è registrato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Nessuna parte del SIS II è collegata a sistemi informatici di raccolta ed elaborazione dei dati utilizzati dall’Eurojust o in funzione presso di esso né vi sono trasferiti i dati contenuti nel sistema cui hanno accesso i membri nazionali o i loro assistenti, e nessuna parte del SIS II viene scaricata.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’accesso ai dati inseriti nel SIS II è limitato ai membri nazionali e ai loro assistenti e non si estende al personale dell’Eurojust.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Sono adottate e applicate le misure per garantire sicurezza e riservatezza di cui agli articoli 10 e 11.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"]]}, "42a": {"label": "Articolo 42 bis", "heading": "Accesso ai dati del SIS II da parte delle squadre della guardia di frontiera e costiera europea, di squadre di personale che assolve compiti attinenti al rimpatrio e dei membri delle squadre di sostegno per la gestione della migrazione", "anchor": "art_42a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">A norma dell'articolo 40, paragrafo 8, del regolamento (UE) 2016/1624 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">4</span>\n), i membri delle squadre di cui all'articolo 2, punti 8) e 9), di tale regolamento hanno, nell'ambito dei rispettivi mandati e a condizione che siano autorizzati a effettuare controlli a norma dell'articolo 40, paragrafo 1, della presente decisione e abbiano ricevuto la formazione necessaria a norma dell'articolo 14 della presente decisione, il diritto di accedere ai dati nel SIS II e di consultarli, nella misura in cui ciò sia necessario per l'assolvimento dei loro compiti e sia richiesto dal piano operativo per un'operazione specifica. L'accesso ai dati nel SIS II non è esteso ad altri membri delle squadre.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I membri delle squadre di cui al paragrafo 1 esercitano il diritto di accedere ai dati nel SIS II e di consultarli in conformità del paragrafo 1 tramite un'interfaccia tecnica. L'interfaccia tecnica è istituita e gestita dall'Agenzia europea della guardia di frontiera e costiera e permette un collegamento diretto con il SIS II centrale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Qualora un'interrogazione effettuata da un membro delle squadre di cui al paragrafo 1 del presente articolo riveli l'esistenza di una segnalazione nel SIS II, lo Stato membro segnalante ne è informato. In conformità dell'articolo 40 del regolamento (UE) 2016/1624, i membri delle squadre intervengono esclusivamente in risposta a una segnalazione nel SIS II sotto il controllo e, di norma, in presenza di guardie di frontiera o di personale che assolve compiti attinenti al rimpatrio dello Stato membro ospitante in cui operano. Lo Stato membro ospitante può autorizzare i membri delle squadre ad agire per suo conto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Per verificare la liceità del trattamento dei dati, per l'autocontrollo e per garantire un'adeguata sicurezza e integrità dei dati, l'Agenzia europea della guardia di frontiera e costiera conserva registri di tutti gli accessi al SIS II e le interrogazioni del SIS II in conformità delle disposizioni dell'articolo 12.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L'Agenzia europea della guardia di frontiera e costiera adotta e applica misure per garantire la sicurezza, la riservatezza e l'autocontrollo a norma degli articoli 10, 11 e 13 e provvede affinché le squadre di cui al paragrafo 1 del presente articolo applichino tali misure.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Il presente articolo non pregiudica in alcun modo le disposizioni del regolamento (UE) 2016/1624 concernenti la protezione dei dati né la responsabilità dell'Agenzia europea della guardia di frontiera e costiera per trattamenti non autorizzati o scorretti di tali dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Fatto salvo il paragrafo 2, nessuna parte del SIS II è collegata a un sistema informatico di raccolta e trattamento di dati gestito dalle squadre di cui al paragrafo 1 o dall'Agenzia europea della guardia di frontiera e costiera, e nessun dato nel SIS II a cui hanno accesso tali squadre è trasferito a tale sistema. Nessuna parte del SIS II può essere scaricata o copiata. La registrazione degli accessi e delle interrogazioni non è considerata come scaricamento o duplicazione illecita di dati nel SIS II.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">L'Agenzia europea della guardia di frontiera e costiera consente al Garante europeo della protezione dei dati di sorvegliare ed esaminare le attività svolte dalle squadre di cui al presente articolo nell'esercizio del loro diritto di accesso ai dati nel SIS II e di consultazione degli stessi. Ciò non pregiudica le ulteriori disposizioni del regolamento (UE) 2018/1725 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">5</span>\n).</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "43": {"label": "Articolo 43", "heading": "Ambito dell’accesso", "anchor": "art_43", "frags": [[null, "<p class=\"norm\">Gli utenti, compreso l’Europol, i membri nazionali dell’Eurojust e i loro assistenti, possono accedere solo ai dati necessari per l’assolvimento dei loro compiti.</p>"]]}, "44": {"label": "Articolo 44", "heading": "Termini di conservazione delle segnalazioni relative a persone", "anchor": "art_44", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le segnalazioni relative alle persone inserite nel SIS II a norma della presente decisione sono conservate esclusivamente per il periodo necessario a realizzare gli obiettivi per i quali sono state inserite.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Uno Stato membro che ha effettuato una segnalazione riesamina la necessità di conservarla nel SIS II entro tre anni dall’inserimento nello stesso. Il periodo è ridotto a un anno per le segnalazioni relative alle persone di cui all’articolo 36.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro fissa, se del caso, tempi di riesame più brevi conformemente alla propria legislazione nazionale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Nel periodo di riesame uno Stato membro che effettua la segnalazione può, a seguito di una valutazione individuale approfondita, decidere di mantenerla più a lungo, ove ciò sia necessario per gli scopi che sono alla base della segnalazione stessa. In tal caso il paragrafo 2 si applica anche a tale prolungamento. Ogni prolungamento di una segnalazione è comunicato al CS-SIS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le segnalazioni sono cancellate automaticamente allo scadere del periodo di riesame di cui al paragrafo 2, salvo qualora lo Stato membro che ha effettuato la segnalazione abbia comunicato il prolungamento della stessa al CS-SIS a norma del paragrafo 4. Il CS-SIS segnala automaticamente agli Stati membri, con quattro mesi d’anticipo, la prevista cancellazione di dati dal sistema.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli Stati membri tengono statistiche sul numero di segnalazioni il cui periodo di conservazione è stato prolungato a norma del paragrafo 4.</div>\n</div>"]]}, "45": {"label": "Articolo 45", "heading": "Termini di conservazione delle segnalazioni relative a oggetti", "anchor": "art_45", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le segnalazioni relative ad oggetti inserite nel SIS II a norma della presente decisione sono conservate esclusivamente per il periodo necessario a realizzare gli obiettivi per i quali sono state inserite.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le segnalazioni relative ad oggetti inserite a norma dell’articolo 36 sono conservate al massimo per cinque anni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le segnalazioni relative ad oggetti inserite a norma dell’articolo 38 sono conservate al massimo per dieci anni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I termini di conservazione di cui ai paragrafi 2 e 3 possono essere prorogati, ove ciò sia necessario per gli scopi che sono alla base della segnalazione stessa. In tal caso, i paragrafi 2 e 3 si applicano anche alla proroga.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "46": {"label": "Articolo 46", "heading": "Trattamento dei dati SIS II", "anchor": "art_46", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono trattare i dati di cui agli articoli 20, 26, 32, 34, 36 e 38 solo ai fini enunciati per ciascuna delle categorie di segnalazioni di cui a tali articoli.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I dati possono essere duplicati soltanto per fini tecnici, sempreché tale operazione sia necessaria per la consultazione diretta da parte delle autorità di cui all’articolo 40. Le disposizioni della presente decisione si applicano a tali copie. Le segnalazioni effettuate da uno Stato membro non possono essere copiate dal proprio N.SIS II in altri archivi di dati nazionali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le copie tecniche di cui al paragrafo 2 che portano alla creazione di banche dati off-line possono essere conservate solo per un periodo non superiore a quarantotto ore. Tale periodo può essere esteso in caso di emergenza, finché l’emergenza non sia cessata.</p>\n<p class=\"norm inline-element\">Gli Stati membri mantengono un inventario aggiornato di tali copie, lo rendono accessibile alle loro autorità nazionali di controllo e assicurano che le disposizioni della presente decisione, in particolare quelle dell’articolo 10, vengano applicate a tali copie.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’accesso ai dati è autorizzato esclusivamente nei limiti delle competenze delle autorità nazionali di cui all’articolo 40 e riservato al personale debitamente autorizzato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Per quanto riguarda le segnalazioni di cui agli articoli 26, 32, 34, 36 e 38 della presente decisione, ogni trattamento delle informazioni in esse contenute per fini diversi da quelli per i quali sono state inserite nel SIS II deve essere connesso a un caso specifico e giustificato dalla necessità di prevenire una minaccia grave imminente per l’ordine pubblico e la sicurezza pubblica, per fondati motivi di sicurezza nazionale o ai fini della prevenzione di un reato grave. A tale scopo deve essere ottenuta l’autorizzazione preventiva dello Stato membro che effettua la segnalazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">I dati non possono essere usati a scopi amministrativi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Qualsiasi uso dei dati non conforme ai paragrafi da 1 a 6 è considerato un uso illegale ai sensi della legislazione di ciascuno Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro invia all’organo di gestione un elenco delle proprie autorità competenti autorizzate a consultare direttamente i dati inseriti nel SIS II a norma della presente decisione e delle eventuali modifiche apportate all’elenco. L’elenco indica per ciascuna autorità i dati che essa può consultare e a quali fini. L’organo di gestione provvede alla pubblicazione annuale dell’elenco nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Sempreché il diritto dell’Unione europea non preveda disposizioni particolari, la legislazione di ciascuno Stato membro si applica ai dati inseriti nel rispettivo N.SIS II.</div>\n</div>"]]}, "47": {"label": "Articolo 47", "heading": "Dati SIS II e archivi nazionali", "anchor": "art_47", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’articolo 46, paragrafo 2, non pregiudica il diritto di uno Stato membro di conservare nel proprio archivio nazionale i dati SIS II in collegamento con i quali è stata svolta un’azione nel suo territorio. Tali dati sono conservati negli archivi nazionali per un periodo massimo di tre anni, a meno che disposizioni specifiche di diritto nazionale prevedano un periodo di conservazione più lungo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’articolo 46, paragrafo 2, non pregiudica il diritto di uno Stato membro di conservare nel proprio archivio nazionale i dati contenuti in una segnalazione particolare effettuata nel SIS II da quello stesso Stato membro.</div>\n</div>"]]}, "48": {"label": "Articolo 48", "heading": "Informazione in caso di mancata esecuzione di una segnalazione", "anchor": "art_48", "frags": [[null, "<p class=\"norm\">Se l’azione richiesta non può essere eseguita, lo Stato membro a cui è stata presentata la richiesta ne informa senza indugio lo Stato membro che ha effettuato la segnalazione.</p>"]]}, "49": {"label": "Articolo 49", "heading": "Qualità dei dati trattati nel SIS II", "anchor": "art_49", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Uno Stato membro che effettua una segnalazione è responsabile dell’esattezza, dell’attualità e della liceità di inserimento dei dati nel SIS II.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Solo lo Stato membro che ha effettuato una segnalazione è autorizzato a modificare, completare, rettificare, aggiornare o cancellare i dati che ha inserito.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se uno Stato membro diverso da quello che ha effettuato una segnalazione è in possesso di elementi che dimostrano che detti dati contengono errori di fatto o sono stati archiviati illecitamente, ne informa quanto prima, tramite scambio di informazioni supplementari ed entro dieci giorni dacché è in possesso di detti elementi, lo Stato membro che ha effettuato la segnalazione. Quest’ultimo verifica la comunicazione e, se necessario, rettifica o cancella senza indugio i dati in questione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Se entro due mesi gli Stati membri non giungono a un accordo, lo Stato membro che non ha effettuato la segnalazione sottopone la questione al garante europeo della protezione dei dati, il quale, insieme alle autorità nazionali di controllo interessate, agisce in qualità di mediatore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri si scambiano informazioni supplementari se una persona presenta un ricorso nel quale fa valere di non essere la persona oggetto della segnalazione. Se dalla verifica risulta che si tratta in effetti di due persone distinte, il ricorrente è informato delle disposizioni dell’articolo 51.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Se una persona è già segnalata nel SIS II, lo Stato membro che introduce un’altra segnalazione si accorda in merito a tale inserimento con lo Stato membro che ha effettuato la prima segnalazione. L’accordo è raggiunto sulla base allo scambio di informazioni supplementari.</div>\n</div>"]]}, "50": {"label": "Articolo 50", "heading": "Distinzione tra persone con caratteristiche simili", "anchor": "art_50", "frags": [[null, "<p class=\"norm\">Quando, inserendo una nuova segnalazione, risulta evidente che nel SIS II è già registrata una persona che possiede gli stessi elementi di descrizione dell’identità, occorre seguire la procedura seguente:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’ufficio Sirene si mette in contatto con l’autorità richiedente allo scopo di verificare se la segnalazione riguardi o meno la stessa persona;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se da tale controllo incrociato risulta che la persona oggetto di una nuova segnalazione e la persona già registrata nel SIS II sono la stessa, l’ufficio Sirene applica la procedura per l’inserimento di segnalazioni multiple di cui all’articolo 49, paragrafo 6. Qualora si stabilisca che si tratta di due persone diverse, l’ufficio Sirene convalida la richiesta di inserimento della seconda segnalazione aggiungendo gli elementi necessari per evitare errori di identificazione.</p>\n</div>\n</div>"]]}, "51": {"label": "Articolo 51", "heading": "Dati complementari per trattare i casi di usurpazione di identità", "anchor": "art_51", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Quando sono possibili confusioni fra la persona effettivamente oggetto di una segnalazione e una persona la cui identità è stata usurpata, lo Stato membro che ha introdotto la segnalazione vi aggiunge, con il consenso esplicito della persona interessata, dati che la riguardano per evitare le conseguenze negative di un errore di identificazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I dati relativi alla vittima dell’usurpazione di identità sono usati soltanto ai seguenti fini:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">consentire all’autorità competente di distinguere la persona la cui identità è stata usurpata dalla persona effettivamente oggetto della segnalazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">permettere alla persona la cui identità è stata usurpata di dimostrare la propria identità e stabilire di essere stata vittima di un’usurpazione di identità.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ai fini del presente articolo possono essere inseriti e successivamente trattati nel SIS II solo i seguenti dati personali:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognomi e nomi, cognomi alla nascita, eventuali cognomi precedenti e «alias» eventualmente registrati a parte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">segni fisici particolari, oggettivi ed inalterabili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">luogo e data di nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fotografie;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impronte digitali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cittadinanza(e);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">numero del o dei documenti d’identità e data del rilascio.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le norme tecniche necessarie per l’inserimento e l’ulteriore trattamento dei dati di cui al paragrafo 3 sono stabilite secondo la procedura di cui all’articolo 67, fatte salve le disposizioni dello strumento che istituisce l’organo di gestione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I dati di cui al paragrafo 3 sono cancellati insieme con la segnalazione corrispondente o prima su richiesta dell’interessato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Possono accedere ai dati di cui al paragrafo 3 soltanto le autorità che hanno diritto di accesso alla segnalazione corrispondente e all’unico scopo di evitare errori di identificazione.</div>\n</div>"]]}, "52": {"label": "Articolo 52", "heading": "Connessioni fra segnalazioni", "anchor": "art_52", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può creare una connessione tra le segnalazioni che introduce nel SIS II. Effetto della connessione è istaurare un nesso fra due o più segnalazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La creazione di una connessione non incide sulla specifica azione da intraprendere sulla base di ciascuna segnalazione interconnessa né sul rispettivo termine di conservazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La creazione di una connessione non incide sui diritti di accesso previsti nella presente decisione. Le autorità che non hanno diritto di accesso a talune categorie di segnalazioni non sono in grado di visualizzare la connessione a una segnalazione cui non hanno accesso.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Uno Stato membro crea una connessione tra segnalazioni solo se sussiste una reale esigenza operativa.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può creare connessioni conformemente alla legislazione nazionale purché siano rispettati i principi enunciati nel presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Uno Stato membro, qualora ritenga che la creazione di una connessione tra segnalazioni da parte di un altro Stato membro sia incompatibile con la sua legislazione nazionale o i suoi obblighi internazionali, può adottare le necessarie disposizioni affinché non sia possibile accedere alla connessione dal suo territorio nazionale o per le sue autorità dislocate al di fuori del suo territorio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Le norme tecniche per la connessione delle segnalazioni sono adottate secondo la procedura di cui all’articolo 67, fatte salve le disposizioni dello strumento che istituisce l’organo di gestione.</div>\n</div>"]]}, "53": {"label": "Articolo 53", "heading": "Finalità e termini di conservazione delle informazioni supplementari", "anchor": "art_53", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri conservano un riferimento alle decisioni di effettuare una segnalazione presso l’ufficio Sirene, a sostegno dello scambio di informazioni supplementari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I dati personali archiviati dall’ufficio Sirene in seguito allo scambio di informazioni sono conservati soltanto per il tempo necessario a conseguire gli scopi per i quali sono stati forniti. Essi sono in ogni caso cancellati al più tardi un anno dopo che è stata cancellata dal SIS II la relativa segnalazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il paragrafo 2 non pregiudica il diritto di uno Stato membro di conservare negli archivi nazionali i dati relativi ad una determinata segnalazione effettuata da detto Stato membro o ad una segnalazione in collegamento con la quale è stata intrapresa un’azione nel suo territorio. Il periodo per cui tali dati possono essere conservati in tali archivi è regolato dalla legislazione nazionale.</div>\n</div>"]]}, "54": {"label": "Articolo 54", "heading": "Trasferimento di dati personali a terzi", "anchor": "art_54", "frags": [[null, "<p class=\"norm\">I dati trattati nel SIS II a norma della presente decisione non sono trasferiti a paesi terzi o a organizzazioni internazionali, né sono messi a loro disposizione.</p>"]]}, "55": {"label": "Articolo 55", "heading": "Scambio di dati con l’Interpol sui passaporti rubati, altrimenti sottratti, smarriti o falsificati", "anchor": "art_55", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 54 il numero, il paese di rilascio e la tipologia dei passaporti rubati, altrimenti sottratti, smarriti o falsificati inseriti nel SIS II possono essere scambiati con membri dell’Interpol stabilendo un collegamento tra il SIS II e la banca dati dell’Interpol sui documenti di viaggio rubati o smarriti, fatta salva la conclusione di un accordo tra l’Interpol e l’Unione europea. In base a tale accordo la trasmissione di dati inseriti da uno Stato membro è soggetta al consenso di tale Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’accordo di cui al paragrafo 1 prevede che i dati condivisi siano accessibili solo a membri dell’Interpol di paesi che assicurano un adeguato livello di protezione dei dati personali. Prima di concludere l’accordo, il Consiglio chiede il parere della Commissione sull’adeguatezza del livello di protezione dei dati personali e di rispetto dei diritti e delle libertà fondamentali per quanto riguarda il trattamento automatizzato dei dati personali da parte dell’Interpol e da parte dei paesi che hanno distaccato membri presso l’Interpol.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’accordo di cui al paragrafo 1 può anche prevedere che gli Stati membri abbiano accesso, attraverso il SIS II, ai dati della banca dati dell’Interpol sui documenti di viaggio rubati o smarriti, in conformità delle pertinenti disposizioni della presente decisione che disciplinano le segnalazioni sui passaporti rubati, altrimenti sottratti, smarriti o falsificati inserite nel SIS II.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "56": {"label": "Articolo 56", "heading": "Trattamento di categorie di dati sensibili", "anchor": "art_56", "frags": [[null, "<p class=\"norm\">È vietato il trattamento delle categorie di dati elencati nell’articolo 6, prima frase, della convenzione del Consiglio d’Europa, del 28 gennaio 1981, sulla protezione delle persone rispetto al trattamento automatizzato di dati di carattere personale.</p>"]]}, "57": {"label": "Articolo 57", "heading": "Applicazione della convenzione del Consiglio d’Europa sulla protezione dei dati", "anchor": "art_57", "frags": [[null, "<p class=\"norm\">I dati personali trattati in applicazione della presente decisione sono protetti a norma della convenzione del Consiglio d’Europa, del 28 gennaio 1981, sulla protezione delle persone rispetto al trattamento automatizzato di dati di carattere personale, e successive modifiche.</p>"]]}, "58": {"label": "Articolo 58", "heading": "Diritto di accesso, rettifica di dati inesatti e cancellazione di dati archiviati illecitamente", "anchor": "art_58", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il diritto di una persona di accedere ai dati che la riguardano inseriti nel SIS II conformemente alla presente decisione è esercitato nel rispetto della legislazione dello Stato membro presso il quale l’interessato lo fa valere.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ove previsto dalla legislazione nazionale, l’autorità nazionale di controllo decide se ed in base a quali modalità deve comunicare informazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Uno Stato membro diverso da quello che ha effettuato una segnalazione può comunicare informazioni su tali dati soltanto se dà prima la possibilità allo Stato membro che ha effettuato la segnalazione di prendere posizione. A ciò si provvede tramite lo scambio di informazioni supplementari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’informazione non è comunicata alla persona interessata se ciò è indispensabile per l’esecuzione di un compito legittimo connesso con una segnalazione o ai fini della tutela dei diritti e delle libertà di terzi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Chiunque ha il diritto di far rettificare dati che lo riguardano contenenti errori di fatto o di far cancellare dati che lo riguardano inseriti illecitamente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’interessato è informato prima possibile e comunque non oltre 60 giorni dalla data in cui ha chiesto l’accesso o prima, se la legislazione nazionale lo prevede.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">L’interessato è informato del seguito dato all’esercizio del suo diritto di rettifica e cancellazione prima possibile e comunque non oltre tre mesi dalla data in cui ha chiesto la rettifica o la cancellazione o prima, se la legislazione nazionale lo prevede.</div>\n</div>"]]}, "59": {"label": "Articolo 59", "heading": "Mezzi di impugnazione", "anchor": "art_59", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Chiunque può adire la giurisdizione o l’autorità competente in base alla legislazione di qualsiasi Stato membro per accedere, rettificare, cancellare o ottenere informazioni o per ottenere un indennizzo relativamente ad una segnalazione che lo riguarda.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri si impegnano reciprocamente ad eseguire le decisioni definitive emesse dalle giurisdizioni o dalle autorità di cui al paragrafo 1, fatte salve le disposizioni dell’articolo 64.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione valuta le norme sui mezzi di impugnazione di cui al presente articolo entro il 23 agosto 2009.</div>\n</div>"]]}, "60": {"label": "Articolo 60", "heading": "Controllo dell’N.SIS II", "anchor": "art_60", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro provvede affinché un’autorità indipendente (l’«autorità nazionale di controllo») controlli autonomamente la liceità del trattamento dei dati personali SIS II nel loro territorio e della loro trasmissione dal loro territorio, compresi lo scambio e il successivo trattamento di informazioni supplementari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’autorità nazionale di controllo provvede affinché venga svolto un controllo delle operazioni di trattamento dei dati nel proprio N.SIS II, conformemente alle norme di revisione internazionali almeno ogni quattro anni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri provvedono affinché la propria autorità di controllo disponga delle risorse sufficienti per assolvere i compiti ad essa assegnati a norma della presente decisione.</div>\n</div>"]]}, "61": {"label": "Articolo 61", "heading": "Controllo dell’organo di gestione", "anchor": "art_61", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il garante europeo della protezione dei dati controlla che le attività di trattamento dei dati personali dell’organo di gestione siano effettuate a norma della presente decisione. Si applicano di conseguenza i doveri e i poteri di cui agli articoli 46 e 47 del regolamento (CE) n. 45/2001.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il garante europeo della protezione dei dati provvede affinché venga svolto un controllo delle attività di trattamento dei dati personali effettuate dall’organo di gestione, conformemente alle norme di revisione internazionali almeno ogni quattro anni. Una relazione su tale controllo è trasmessa al Parlamento europeo, al Consiglio, all’organo di gestione, alla Commissione e alle autorità nazionali di controllo. L’organo di gestione ha l’opportunità di presentare le sue osservazioni prima dell’adozione della relazione.</div>\n</div>"]]}, "62": {"label": "Articolo 62", "heading": "Cooperazione tra le autorità nazionali di controllo e il garante europeo della protezione dei dati", "anchor": "art_62", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le autorità nazionali di controllo e il garante europeo della protezione dei dati, ciascuno nell’ambito delle proprie competenze, cooperano attivamente nel quadro delle rispettive responsabilità e assicurano il controllo coordinato del SIS II.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se necessario, ciascuno nell’ambito delle proprie competenze, essi si scambiano informazioni pertinenti, si assistono reciprocamente nello svolgimento di revisioni e ispezioni, esaminano difficoltà di interpretazione o applicazione della presente decisione, studiano problemi inerenti all’esercizio di un controllo indipendente o all’esercizio dei diritti delle persone cui i dati si riferiscono, elaborano proposte armonizzate per soluzioni congiunte di eventuali problemi e promuovono la sensibilizzazione del pubblico in materia di diritti di protezione dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le autorità nazionali di controllo e il garante europeo della protezione dei dati si riuniscono a tal fine almeno due volte l’anno. I costi di tali riunioni e la gestione delle stesse sono a carico del garante europeo della protezione dei dati. Nella prima riunione è adottato un regolamento interno. Ulteriori metodi di lavoro sono elaborati congiuntamente, se necessario. Ogni due anni è trasmessa al Parlamento europeo, al Consiglio, alla Commissione e all’organo di gestione una relazione congiunta sulle attività svolte.</div>\n</div>"]]}, "63": {"label": "Articolo 63", "heading": "Protezione dei dati durante il periodo transitorio", "anchor": "art_63", "frags": [[null, "<p class=\"norm\">La Commissione, qualora durante il periodo transitorio deleghi le sue competenze ad un altro organismo o ad altri organismi, a norma dell’articolo 15, paragrafo 4, provvede affinché il garante europeo della protezione dei dati abbia la facoltà e sia in grado di svolgere pienamente i suoi compiti, compresa l’effettuazione di controlli in loco o l’esercizio dei poteri attribuitigli dall’articolo 47 del regolamento (CE) n. 45/2001.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "64": {"label": "Articolo 64", "heading": "Responsabilità", "anchor": "art_64", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro è responsabile, conformemente alla propria legislazione nazionale, dei danni causati ad una persona in seguito all’uso dell’N.SIS II. La disposizione si applica anche quando i danni sono stati causati dallo Stato membro che ha effettuato la segnalazione, ove abbia inserito dati contenenti errori di fatto o archiviato i dati in modo illecito.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se lo Stato membro avverso il quale è promossa un’azione non è lo Stato membro che ha effettuato la segnalazione, quest’ultimo è tenuto al rimborso, su richiesta, delle somme versate a titolo di risarcimento, a meno che l’uso dei dati da parte dello Stato membro che ha chiesto il rimborso violi la presente decisione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se l’inosservanza da parte di uno Stato membro degli obblighi derivanti dalla presente decisione causa danni al SIS II, tale Stato membro ne risponde, a meno che e nella misura in cui l’organo di gestione o un altro Stato membro partecipanti al SIS II non abbiano omesso di adottare le misure ragionevolmente necessarie a evitare tali danni o a minimizzarne gli effetti.</div>\n</div>"]]}, "65": {"label": "Articolo 65", "heading": "Sanzioni", "anchor": "art_65", "frags": [[null, "<p class=\"norm\">Gli Stati membri provvedono affinché l’eventuale uso improprio dei dati inseriti nel SIS II o qualsiasi scambio di informazioni supplementari contrario alla presente decisione sia punito con sanzioni effettive, proporzionate e dissuasive conformemente alla legislazione nazionale.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "66": {"label": "Articolo 66", "heading": "Controllo e statistiche", "anchor": "art_66", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’organo di gestione provvede affinché siano attivate procedure atte a controllare il funzionamento del SIS II in rapporto a obiettivi di risultato, economicità, sicurezza e qualità del servizio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ai fini della manutenzione tecnica, delle relazioni e delle statistiche, l’organo di gestione ha accesso alle informazioni necessarie riguardanti le operazioni di trattamento effettuate nel SIS II centrale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ogni anno l’organo di gestione pubblica statistiche, sia totali sia per ciascuno Stato membro, relative al numero di registri per categoria di segnalazione, al numero di risposte positive per categoria di segnalazione e al numero di accessi al SIS II.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Due anni dopo l’inizio delle attività del SIS II e successivamente ogni due anni, l’organo di gestione presenta al Parlamento europeo e al Consiglio una relazione sul funzionamento tecnico del SIS II centrale e dell’infrastruttura di comunicazione, compresa la sicurezza dello stesso e lo scambio bilaterale e multilaterale di informazioni supplementari fra Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Tre anni dopo l’inizio delle attività del SIS II e successivamente ogni quattro anni, la Commissione presenta una valutazione globale del SIS II centrale e dello scambio bilaterale e multilaterale di informazioni supplementari fra Stati membri. Tale valutazione globale comprende un’analisi dei risultati conseguiti rispetto agli obiettivi e una valutazione circa la validità dei principi di base, l’applicazione della presente decisione con riguardo al SIS II centrale, la sicurezza del SIS II centrale e le eventuali implicazioni per le attività future. La Commissione trasmette la valutazione al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli Stati membri comunicano all’organo di gestione e alla Commissione le informazioni necessarie per redigere le relazioni di cui ai paragrafi 3, 4 e 5.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">L’organo di gestione comunica alla Commissione le informazioni necessarie per presentare le valutazioni globali di cui al paragrafo 5.</div>\n</div>"]]}, "67": {"label": "Articolo 67", "heading": "Comitato di regolamentazione", "anchor": "art_67", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente articolo, la Commissione è assistita da un comitato di regolamentazione composto dei rappresentanti degli Stati membri e presieduto dal rappresentante della Commissione. Il rappresentante della Commissione sottopone al comitato un progetto delle misure da adottare. Il comitato esprime il suo parere sul progetto entro un termine che il presidente può fissare in funzione dell’urgenza della questione in esame. Il parere è formulato alla maggioranza prevista all’articolo 205, paragrafo 2, del trattato CE per l’adozione delle decisioni che il Consiglio deve prendere su proposta della Commissione. Nelle votazioni del comitato, ai voti dei rappresentanti degli Stati membri è attribuita la ponderazione definita in quell’articolo. Il presidente non partecipa al voto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il comitato adotta il proprio regolamento interno su proposta del presidente, basandosi su un modello di regolamento interno pubblicato nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione adotta le misure previste qualora siano conformi al parere del comitato. Se le misure previste non sono conformi al parere del comitato, o in assenza di parere, la Commissione sottopone senza indugio al Consiglio una proposta in merito alle misure da adottare.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il Consiglio può deliberare sulla proposta a maggioranza qualificata entro due mesi dalla data in cui gli è stata presentata la proposta. Se entro tale termine il Consiglio ha manifestato a maggioranza qualificata la sua opposizione alla proposta, la Commissione la riesamina. Essa può presentare al Consiglio una proposta modificata, ripresentare la proposta ovvero presentare una proposta legislativa. Se allo scadere di tale termine il Consiglio non ha adottato l’atto di esecuzione proposto ovvero non ha manifestato opposizione alla proposta di misure di esecuzione, la Commissione adotta l’atto di esecuzione proposto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il comitato di cui al paragrafo 1 esercita la sua funzione a partire dal 23 agosto2007.</div>\n</div>"]]}, "68": {"label": "Articolo 68", "heading": "Modifica delle disposizioni dell’acquis di Schengen", "anchor": "art_68", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per le materie che rientrano nell’ambito di applicazione del trattato UE, la presente decisione sostituisce, alla data di cui all’articolo 71, paragrafo 2, le disposizioni degli articoli 64 e da 92 a 119 della convenzione di Schengen, salvo l’articolo 102 <span class=\"italics\">bis</span>.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per le materie che rientrano nell’ambito di applicazione del trattato UE, la presente decisione sostituisce, alla data di cui all’articolo 71, paragrafo 2, le seguenti disposizioni dell’acquis di Schengen che attuano quegli articoli (\n<span class=\"superscript\">6</span>\n):</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">decisione del comitato esecutivo, del 14 dicembre 1993, relativa al regolamento finanziario riguardante le spese relative all’installazione e al funzionamento del sistema d’informazione Schengen (C.SIS) [SCH/Com-ex (93) 16];</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">decisione del comitato esecutivo, del 7 ottobre 1997, riguardante l’evoluzione del SIS [SCH/Com-ex (97) 24];</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">decisione del comitato esecutivo, del 15 dicembre 1997, riguardante la modifica del regolamento finanziario C.SIS [SCH/Com-ex (97) 35];</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">decisione del comitato esecutivo, del 21 aprile 1998, riguardante il C.SIS con 15/18 collegamenti [SCH/Com-ex (98) 11];</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">decisione del comitato esecutivo, del 25 aprile 1997, relativa all’aggiudicazione dello studio preliminare del SIS II [SCH/Com-ex (97) 2, rev. 2];</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">decisione del comitato esecutivo, del 28 aprile 1999, riguardante i costi d’installazione del C.SIS [SCH/Com-ex (99) 4];</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">decisione del comitato esecutivo, del 28 aprile 1999, riguardante l’aggiornamento del manuale Sirene [SCH/Com-ex (99) 5];</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dichiarazione del comitato esecutivo, del 18 aprile 1996, relativa alla definizione del concetto di straniero [SCH/Com-ex (96) decl. 5];</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dichiarazione del comitato esecutivo, del 28 aprile 1999, riguardante la struttura del SIS [SCH/Com-ex (99) decl. 2 rev.];</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">decisione del comitato esecutivo, del 7 ottobre 1997, riguardante il contributo della Norvegia e dell’Islanda alle spese d’installazione e di funzionamento del C.SIS [SCH/Com-ex (97) 18].</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Per le materie che rientrano nell’ambito di applicazione del trattato UE, i riferimenti agli articoli della convenzione di Schengen così sostituiti e alle pertinenti disposizioni dell’acquis di Schengen che li attuano si intendono fatti alla presente decisione.</div>\n</div>"]]}, "69": {"label": "Articolo 69", "heading": "Abrogazione", "anchor": "art_69", "frags": [[null, "<p class=\"norm\">Alla data di cui all’articolo 71, paragrafo 2, sono abrogate le decisioni 2004/201/GAI, 2005/211/GAI, 2005/719/GAI, 2005/727/GAI, 2006/228/GAI, 2006/229/GAI e 2006/631/GAI.</p>"]]}, "70": {"label": "Articolo 70", "heading": "Periodo transitorio e bilancio", "anchor": "art_70", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le segnalazioni sono trasferite dal SIS 1+ al SIS II. Gli Stati membri assicurano, attribuendo la priorità alle segnalazioni di persone, che il contenuto delle segnalazioni trasferite dal SIS 1+ al SIS II sia conforme alle disposizioni della presente decisione prima possibile e al più tardi entro tre anni dalla data di cui all’articolo 71, paragrafo 2. Nel periodo transitorio gli Stati membri possono continuare ad applicare gli articoli 94, 95 e da 97 a 100 della convenzione di Schengen al contenuto delle segnalazioni trasferite dal SIS 1+ al SIS II, fatte salve le seguenti regole:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in caso di modifica, complemento, rettifica o aggiornamento del contenuto di una segnalazione trasferita dal SIS 1+ al SIS II, gli Stati membri assicurano che la segnalazione sia conforme alle disposizioni della presente decisione a decorrere dall’introduzione della modifica, complemento, rettifica o aggiornamento in questione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in caso di risposta positiva su una segnalazione trasferita dal SIS 1+ al SIS II, gli Stati membri esaminano immediatamente la compatibilità di tale segnalazione con le disposizioni della presente decisione senza tuttavia ritardare l’azione da intraprendere in base alla stessa.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Alla data fissata a norma dell’articolo 71, paragrafo 2, il residuo del bilancio approvato in conformità delle disposizioni dell’articolo 119 della convenzione di Schengen è restituito agli Stati membri. Gli importi da restituire sono calcolati in base ai contributi degli Stati membri in conformità della decisione del comitato esecutivo, del 14 dicembre 1993, relativa al regolamento finanziario riguardante le spese relative all’installazione e al funzionamento del SIS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Durante il periodo transitorio di cui all’articolo 15, paragrafo 4, i riferimenti, nella presente decisione, all’organo di gestione si intendono fatti alla Commissione.</div>\n</div>"]]}, "71": {"label": "Articolo 71", "heading": "Entrata in vigore, applicabilità e migrazione", "anchor": "art_71", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La presente decisione entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Essa si applica agli Stati membri partecipanti al SIS 1+ a partire dalle date che il Consiglio stabilirà, deliberando all’unanimità dei suoi membri che rappresentano i governi degli Stati membri partecipanti al SIS 1+.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le date di cui al paragrafo 2 sono stabilite:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una volta adottate le necessarie disposizioni di attuazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">quando tutti gli Stati membri partecipanti a pieno titolo al SIS 1+ avranno notificato alla Commissione di aver adottato le disposizioni tecniche e giuridiche necessarie per trattare i dati SIS II e scambiare informazioni supplementari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">quando la Commissione avrà dichiarato che è stato ultimato con esito positivo un test globale del SIS II, condotto dalla Commissione con gli Stati membri, e gli organi preparatori del Consiglio avranno convalidato i risultati proposti del test e confermato che il livello di prestazione del SIS II è almeno equivalente a quello già garantito dal SIS 1+;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">quando la Commissione avrà adottato le necessarie disposizioni tecniche per consentire la connessione del SIS II centrale all’N.SIS II degli Stati membri interessati.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione comunica al Parlamento europeo i risultati del test condotto a norma del paragrafo 3, lettera c).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Qualsiasi decisione del Consiglio presa ai sensi del paragrafo 2 è pubblicata nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>.</div>\n</div>"], [null, "<p>\n<br/>\n</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">1</span>\n) GU L 248 del 16.9.2002, pag. 1.</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">2</span>\n) GU L 105 del 13.4.2006, pag. 1.</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">3</span>\n) Regolamento (UE) 2016/794 del Parlamento europeo e del Consiglio, dell'11 maggio 2016, che istituisce l'Agenzia dell'Unione europea per la cooperazione nell'attività di contrasto (Europol) e sostituisce e abroga le decisioni del Consiglio 2009/371/GAI, 2009/934/GAI, 2009/935/GAI, 2009/936/GAI e 2009/968/GAI (GU L 135 del 24.5.2016, pag. 53).</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">4</span>\n) Regolamento (UE) 2016/1624 del Parlamento europeo e del Consiglio, del 14 settembre 2016, relativo alla guardia di frontiera e costiera europea che modifica il regolamento (UE) 2016/399 del Parlamento europeo e del Consiglio e che abroga il regolamento (CE) n. 863/2007 del Parlamento europeo e del Consiglio, il regolamento (CE) n. 2007/2004 del Consiglio e la decisione 2005/267/CE del Consiglio (GU L 251 del 16.9.2016, pag. 1).</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">5</span>\n) Regolamento (UE) 2018/1725 del Parlamento europeo e del Consiglio, del 23 ottobre 2018, sulla tutela delle persone fisiche in relazione al trattamento dei dati personali da parte delle istituzioni, degli organi e degli organismi dell'Unione e sulla libera circolazione di tali dati, e che abroga il regolamento (CE) n. 45/2001 e la decisione n. 1247/2002/CE (GU L 295 del 21.11.2018, pag. 39).</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">6</span>\n) GU L 239 del 22.9.2000, pag. 439.</p>"]]}}, "recitals": {}};